    # A simple heuristic to classify combinations
    # For demonstration, we classify based on the number of unique bricks
    unique_bricks = len(set(combination))
    if unique_bricks <= 2:
        return 'Simple'
    elif unique_bricks <= 4:
        return 'Moderate'
    else:
        return 'Complex'

