    brick_count = 6
    total_ways = count_ways(brick_count)
    print(f"Total ways to combine {brick_count} bricks: {total_ways}")

    # Example combinations for classification
    example_combinations = [
        (1, 1, 2, 2, 3, 3),
        (1, 1, 1, 2, 2, 3),
        (1, 2, 3, 4, 5, 6),
        (1, 1, 1, 1, 1, 1)
    ]

    for combination in example_combinations:
        classification = classify_combination(combination)
        print(f"Combination {combination} is classified as: {classification}")

